"use client";

import React, { useState, useEffect } from "react";
import axios from "axios";
import VoiceInput from "@/components/VoiceInput";
import ScreenPreview from "@/components/ScreenPreview";
import ActionLog from "@/components/ActionLog";
import { Cpu, ShieldCheck, Zap } from "lucide-react";

const API_BASE_URL = "http://localhost:8000";

export default function Home() {
  const [taskId, setTaskId] = useState<string | null>(null);
  const [taskStatus, setTaskStatus] = useState<any>({
    status: "idle",
    logs: [],
    last_screenshot: null
  });
  const [isProcessing, setIsProcessing] = useState(false);

  useEffect(() => {
    let interval: any;
    if (taskId && (taskStatus.status === "running" || taskStatus.status === "starting")) {
      interval = setInterval(async () => {
        try {
          const response = await axios.get(`${API_BASE_URL}/task/${taskId}`);
          setTaskStatus(response.data);
          
          if (response.data.status === "completed" || response.data.status === "failed") {
            setIsProcessing(false);
            clearInterval(interval);
          }
        } catch (error) {
          console.error("Error polling task:", error);
        }
      }, 2000);
    }
    return () => clearInterval(interval);
  }, [taskId, taskStatus.status]);

  const handleSendCommand = async (command: string) => {
    setIsProcessing(true);
    setTaskStatus({ status: "starting", logs: ["Sending command to AI..."], last_screenshot: null });
    
    try {
      const formData = new FormData();
      formData.append("command", command);
      
      const response = await axios.post(`${API_BASE_URL}/execute-task`, formData);
      setTaskId(response.data.task_id);
    } catch (error) {
      console.error("Error starting task:", error);
      setTaskStatus({ 
        status: "failed", 
        logs: ["Failed to connect to backend server."], 
        last_screenshot: null 
      });
      setIsProcessing(false);
    }
  };

  return (
    <main className="max-w-7xl mx-auto px-6 py-12">
      {/* Header */}
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-16">
        <div className="flex items-center gap-3">
          <div className="bg-blue-600 p-3 rounded-2xl shadow-[0_0_20px_rgba(37,99,235,0.4)]">
            <Cpu className="text-white" size={32} />
          </div>
          <div>
            <h1 className="text-3xl font-bold tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
              ScreenPilot
            </h1>
            <p className="text-slate-500 text-sm">Multimodal AI UI Navigator</p>
          </div>
        </div>
        
        <div className="flex items-center gap-6 text-xs text-slate-400 font-medium">
          <div className="flex items-center gap-2">
            <Zap size={14} className="text-yellow-500" />
            <span>Gemini Multimodal</span>
          </div>
          <div className="flex items-center gap-2">
            <ShieldCheck size={14} className="text-green-500" />
            <span>Verified Automation</span>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 mb-8">
        {/* Left Column - Interaction & Logs */}
        <div className="lg:col-span-8 flex flex-col gap-8">
          <ScreenPreview 
            screenshot={taskStatus.last_screenshot} 
            status={taskStatus.status} 
          />
          <VoiceInput 
            onSendCommand={handleSendCommand} 
            isProcessing={isProcessing} 
          />
        </div>

        {/* Right Column - Status & Activity */}
        <div className="lg:col-span-4">
          <ActionLog 
            logs={taskStatus.logs} 
            status={taskStatus.status} 
          />
        </div>
      </div>
      
      {/* Footer Info */}
      <footer className="mt-12 text-center text-slate-600 text-xs">
        <p>© 2026 ScreenPilot AI • Built for Gemini Hackathon</p>
      </footer>
    </main>
  );
}
